// Extract the uploaded file and prepare the Gemini API request body
const item = $input.first();
const binaryKey = Object.keys(item.binary)[0];
const binary = item.binary[binaryKey];
const mimeType = binary.mimeType || 'image/jpeg';
const fileData = binary.data; // already base64 encoded by n8n

const prompt = `You are analyzing a handwritten laundry business ledger page.

Return ONLY valid JSON matching this exact structure — no explanation, no markdown:

{
  "pages": [
    {
      "date": "YYYY-MM-DD",
      "sale_total": 0,
      "entries": [
        {
          "invoice_id": "L-XXXXX",
          "amount": 0,
          "payment_method": "cash",
          "ocr_confidence": 85
        }
      ],
      "failed": false,
      "fail_reason": ""
    }
  ]
}

Rules:
1. date: the date written at the top of the page, in YYYY-MM-DD format.
2. sale_total: ONLY the number written next to the word SALE at the bottom of the page. Ignore all other numbers such as costs or other totals.
3. Each line on the page is one payment entry:
   - invoice_id: the invoice number starting with L- (example: L-33115)
   - amount: the number at the end of the line
   - payment_method: use "card" if the line ends with the letter M, "link" if it ends with the letter L, "cash" if there is no letter at the end
   - ocr_confidence: a number from 0 to 100 representing how clearly you could read this specific line
4. If a page cannot be read at all, set failed to true and explain in fail_reason.
5. For a PDF with multiple pages, return one object per page inside the pages array.

Return ONLY the JSON. Nothing else.`;

return [{
  json: {
    mimeType,
    fileData,
    prompt
  }
}];

// Parse the Gemini API response and extract structured data
const item = $input.first();
const response = item.json;

if (!response.candidates || response.candidates.length === 0) {
  throw new Error('Gemini returned no candidates. Response: ' + JSON.stringify(response).substring(0, 300));
}

const text = response.candidates[0].content.parts[0].text;

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  throw new Error('Gemini response is not valid JSON. Got: ' + text.substring(0, 300));
}

const pages = parsed.pages || [];

return [{
  json: {
    pages,
    total_pages: pages.length,
    failed_pages: pages.filter(p => p.failed).length
  }
}];

// Aggregate all 40k DB rows into a single item with a row number for each row.
// Row 1 is the header, so data starts at row 2.
const allRows = $input.all().map((item, index) => ({
  ...item.json,
  _row_number: index + 2
}));

return [{
  json: {
    dbRows: allRows
  }
}];

// ============================================================
// MATCHING ENGINE
// Receives: aggregated DB rows as input
// Reads: parsed pages from 'Parse Gemini Response' node
// ============================================================

// IMPORTANT: These must match the exact column headers in your Orders DB sheet.
// Adjust these if your column names are different.
const COL_LEGACY_ID       = 'Legacy ID';
const COL_ORDER_ID        = 'Order ID';
const COL_INVOICE_DATE    = 'Invoice Date';
const COL_AMOUNT_PAID     = 'Amount Paid (AED)';
const COL_TOTAL_DISCOUNT  = 'Total After Discount (AED)';
const COL_REMAINING       = 'Remaining Balance (AED)';
const COL_METHOD          = 'Payment Method(s)';
const COL_PAYMENT_DATE    = 'Payment Date(s)';

const dbData = $input.first().json;
const allDbRows = dbData.dbRows;

const parsedData = $('Parse Gemini Response').first().json;
const pages = parsedData.pages || [];

const matchResults   = [];
const parsedEntries  = [];
const salesValidation = [];
const dbUpdates      = [];

for (const page of pages) {

  // --- Failed page: skip matching, log in sales validation ---
  if (page.failed) {
    salesValidation.push({
      Date: page.date || 'UNKNOWN',
      'Parsed Sale Total': 'FAILED',
      'DB Sale Total': '',
      Match: 'FAILED',
      Diff: '',
      Note: page.fail_reason || 'Page could not be read'
    });
    continue;
  }

  const pageDate    = page.date;
  const pageDateObj = new Date(pageDate);

  // --- TASK 2: Sales Validation ---
  const dbRowsForDate = allDbRows.filter(row => {
    if (!row[COL_INVOICE_DATE]) return false;
    return new Date(row[COL_INVOICE_DATE]).toDateString() === pageDateObj.toDateString();
  });

  const dbSaleTotal = dbRowsForDate.reduce((sum, row) => {
    return sum + (parseFloat(row[COL_TOTAL_DISCOUNT]) || 0);
  }, 0);

  const parsedSaleTotal = parseFloat(page.sale_total) || 0;
  const saleDiff = Math.abs(dbSaleTotal - parsedSaleTotal);

  salesValidation.push({
    Date: pageDate,
    'Parsed Sale Total': parsedSaleTotal,
    'DB Sale Total': Math.round(dbSaleTotal * 100) / 100,
    Match: saleDiff <= 1 ? 'YES' : 'NO',
    Diff: Math.round(saleDiff * 100) / 100
  });

  // --- TASK 1: Match each entry ---
  for (const entry of (page.entries || [])) {

    parsedEntries.push({
      Date: pageDate,
      'Order ID': entry.invoice_id,
      'Payment Method': entry.payment_method,
      'Amount Parsed': entry.amount,
      'Confidence Score': entry.ocr_confidence
    });

    // CONTROLLER 1: Exact match on Legacy ID
    const exactMatches = allDbRows.filter(row =>
      (row[COL_LEGACY_ID] || '').trim() === (entry.invoice_id || '').trim()
    );

    if (exactMatches.length === 0) {
      matchResults.push({
        'Page Date': pageDate,
        'Parsed Invoice ID': entry.invoice_id,
        'DB Order ID': '',
        'DB Legacy ID': '',
        'Payment Method (Page)': entry.payment_method,
        'Payment Method (DB)': '',
        'Method Match': 'NO',
        'Amount (Page)': entry.amount,
        'Amount (DB)': '',
        'Amount Match': 'NO',
        'Total After Discount (DB)': '',
        'Remaining Balance (DB)': '',
        'Payment Date (Current)': '',
        'Payment Date (To Update)': pageDate,
        'Match Status': 'NO_MATCH',
        'Flag Reason': 'Invoice ID not found in database',
        'Confidence Score': 0
      });
      continue;
    }

    // CONTROLLER 2: Date window — 6 months back, extend to 12 and flag
    const sixMonthsBack   = new Date(pageDateObj); sixMonthsBack.setMonth(sixMonthsBack.getMonth() - 6);
    const twelveMonthsBack = new Date(pageDateObj); twelveMonthsBack.setMonth(twelveMonthsBack.getMonth() - 12);

    let dateWindowFlag = false;
    let candidates = exactMatches.filter(row => {
      if (!row[COL_INVOICE_DATE]) return false;
      const d = new Date(row[COL_INVOICE_DATE]);
      return d >= sixMonthsBack && d <= pageDateObj;
    });

    if (candidates.length === 0) {
      candidates = exactMatches.filter(row => {
        if (!row[COL_INVOICE_DATE]) return false;
        const d = new Date(row[COL_INVOICE_DATE]);
        return d >= twelveMonthsBack && d <= pageDateObj;
      });
      if (candidates.length > 0) dateWindowFlag = true;
    }

    if (candidates.length === 0) {
      matchResults.push({
        'Page Date': pageDate,
        'Parsed Invoice ID': entry.invoice_id,
        'DB Order ID': '',
        'DB Legacy ID': '',
        'Payment Method (Page)': entry.payment_method,
        'Payment Method (DB)': '',
        'Method Match': 'NO',
        'Amount (Page)': entry.amount,
        'Amount (DB)': '',
        'Amount Match': 'NO',
        'Total After Discount (DB)': '',
        'Remaining Balance (DB)': '',
        'Payment Date (Current)': '',
        'Payment Date (To Update)': pageDate,
        'Match Status': 'NO_MATCH',
        'Flag Reason': 'Invoice found but outside 12 month window',
        'Confidence Score': 0
      });
      continue;
    }

    // CONTROLLER 3: Score each candidate by amount (±1 AED) and payment method
    let bestMatch = null;
    let bestScore = -1;

    for (const row of candidates) {
      let score = 0;
      const dbAmount    = parseFloat(row[COL_AMOUNT_PAID]) || 0;
      const entryAmount = parseFloat(entry.amount) || 0;
      if (Math.abs(dbAmount - entryAmount) <= 1) score++;
      const dbMethod = (row[COL_METHOD] || '').toLowerCase().trim();
      if (dbMethod === entry.payment_method) score++;
      if (score > bestScore) { bestScore = score; bestMatch = row; }
    }

    // Build flags
    const flags       = [];
    const dbAmount    = parseFloat(bestMatch[COL_AMOUNT_PAID]) || 0;
    const entryAmount = parseFloat(entry.amount) || 0;
    const amountMatch = Math.abs(dbAmount - entryAmount) <= 1;
    const dbMethod    = (bestMatch[COL_METHOD] || '').toLowerCase().trim();
    const methodMatch = dbMethod === entry.payment_method;

    if (dateWindowFlag) flags.push('Date window >6m');
    if (!amountMatch)   flags.push(`Amount: page=${entry.amount} DB=${bestMatch[COL_AMOUNT_PAID]}`);
    if (!methodMatch)   flags.push(`Method: page=${entry.payment_method} DB=${bestMatch[COL_METHOD]}`);
    if ((entry.ocr_confidence || 0) < 80) flags.push(`Low OCR conf (${entry.ocr_confidence}%)`);

    // Confidence score: OCR 60% + Amount 15% + Method 15% + Date 10%
    const ocrScore    = (entry.ocr_confidence || 0) * 0.60;
    const amountScore = amountMatch ? 15 : 0;
    const methodScore = methodMatch ? 15 : 0;
    const dateScore   = dateWindowFlag ? 5 : 10;
    const confidenceScore = Math.round(ocrScore + amountScore + methodScore + dateScore);

    const matchStatus = flags.length === 0 ? 'AUTO' : 'FLAG';

    matchResults.push({
      'Page Date': pageDate,
      'Parsed Invoice ID': entry.invoice_id,
      'DB Order ID': bestMatch[COL_ORDER_ID] || '',
      'DB Legacy ID': bestMatch[COL_LEGACY_ID] || '',
      'Payment Method (Page)': entry.payment_method,
      'Payment Method (DB)': bestMatch[COL_METHOD] || '',
      'Method Match': methodMatch ? 'YES' : 'NO',
      'Amount (Page)': entry.amount,
      'Amount (DB)': bestMatch[COL_AMOUNT_PAID] || '',
      'Amount Match': amountMatch ? 'YES' : 'NO',
      'Total After Discount (DB)': bestMatch[COL_TOTAL_DISCOUNT] || '',
      'Remaining Balance (DB)': bestMatch[COL_REMAINING] || '',
      'Payment Date (Current)': bestMatch[COL_PAYMENT_DATE] || '',
      'Payment Date (To Update)': pageDate,
      'Match Status': matchStatus,
      'Flag Reason': flags.join('; '),
      'Confidence Score': confidenceScore
    });

    // Store DB row update info (AUTO and FLAG matches only)
    dbUpdates.push({
      row_number: bestMatch._row_number,
      updated_payment_date: pageDate,
      confidence_score: confidenceScore,
      match_status: matchStatus
    });
  }
}

return [{
  json: { matchResults, parsedEntries, salesValidation, dbUpdates }
}];

const data = $input.first().json;
return data.parsedEntries.length > 0
  ? data.parsedEntries.map(e => ({ json: e }))
  : [{ json: { _skip: true } }];

const data = $input.first().json;
return data.matchResults.length > 0
  ? data.matchResults.map(m => ({ json: m }))
  : [{ json: { _skip: true } }];

// Build a Google Sheets API batchUpdate request to write
// 'Updated Payment Date' and 'Confidence Score' into the Orders DB
// by exact row number.
//
// IMPORTANT: Set the correct column numbers below.
// Count from left starting at 1.
// Example: if 'Updated Payment Date' is the 18th column, set COL_UPDATED_DATE = 18
const COL_UPDATED_DATE  = 18; // <-- SET THIS
const COL_CONFIDENCE    = 19; // <-- SET THIS
const SHEET_TAB_NAME    = 'Sheet1'; // <-- SET THIS to your tab name

const data    = $input.first().json;
const updates = data.dbUpdates || [];

if (updates.length === 0) {
  return [{ json: { skipped: true } }];
}

const batchData = updates.map(u => ({
  range: `${SHEET_TAB_NAME}!R${u.row_number}C${COL_UPDATED_DATE}:R${u.row_number}C${COL_CONFIDENCE}`,
  values: [[u.updated_payment_date, u.confidence_score]]
}));

return [{
  json: {
    valueInputOption: 'USER_ENTERED',
    data: batchData
  }
}];

const data = $input.first().json;
return data.salesValidation.length > 0
  ? data.salesValidation.map(s => ({ json: s }))
  : [{ json: { _skip: true } }];
